// T-slot mounting bracket — an L-bracket with captive M4 nut pockets on the
// vertical leg (for sliding nuts in 2020 aluminium extrusion) and counterbored
// M4 screw holes on the horizontal leg.  A practical, no-tools-needed fastener
// approach common in 3D-printer frames and jigs.
const { Manifold, printFit } = api;

const legLen = 40;   // length of each leg
const legW   = 30;   // width (Y dimension)
const thick  = 5;    // material thickness

// ---- Build the L-shape ----
const horizLeg = Manifold.cube([legLen, legW, thick], false);
const vertLeg  = Manifold.cube([thick, legW, legLen], false);
let bracket = horizLeg.add(vertLeg);

// ---- Horizontal leg: two M4 socket-head counterbored holes from the top ----
for (const hx of [12, 28]) {
  bracket = bracket.subtract(
    printFit.screwHole({ size: 'M4', length: thick, head: 'socket' })
      .translate([hx, legW / 2, thick]),
  );
}

// ---- Vertical leg: two captive M4 nut pockets on the inner (back) face ----
// Nut pockets open toward +X (facing the extrusion slot), inset from the face.
// The socket runs from x=thick (inner face) so subtracting from x=thick outward.
// Rotate so the pocket opens in the +X direction: socket opens at z=0 in printFit,
// so rotate 90° about Y to point +X, then position on the vertical leg.
const nutPocketDepth = 5.5; // deep enough for M4 nut

for (const hz of [12, 28]) {
  // nutPocket returns a tool that opens at z=0 pointing -Z; rotate -90° about X
  // so it opens in +X (toward the extrusion).
  bracket = bracket.subtract(
    printFit.nutPocket({ size: 'M4', depth: nutPocketDepth, captive: true })
      .rotate([-90, 0, 0])
      .rotate([0, 90, 0])
      .translate([thick, legW / 2, hz]),
  );
}

return bracket;
